const items = $input.all();

// Strava liefert pro Aktivität ein Item.
// Dieses Node erzeugt:
// 1) Line Protocol für jede Strava-Aktivität
// 2) Eine kompakte JSON-Zusammenfassung für ChatGPT

function escTag(value) {
  if (value === undefined || value === null || value === '') return 'unknown';
  return String(value)
    .replace(/ /g, '\\ ')
    .replace(/,/g, '\\,')
    .replace(/=/g, '\\=');
}

function escFieldString(value) {
  if (value === undefined || value === null) return '';
  return String(value)
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"')
    .replace(/\n/g, ' ');
}

function num(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

const activities = items
  .map(i => i.json)
  .filter(a => a && (a.id || a.name || a.start_date));

const lines = [];
const compact = [];

for (const a of activities) {
  const id = a.id || `${a.start_date || 'unknown'}_${a.name || 'activity'}`;
  const name = a.name || 'Strava Activity';
  const type = a.type || a.sport_type || 'Activity';
  const start = a.start_date || a.start_date_local || new Date().toISOString();

  const distanceKm = num(a.distance) / 1000;
  const durationMin = num(a.moving_time || a.elapsed_time) / 60;
  const elapsedMin = num(a.elapsed_time) / 60;
  const elevationM = num(a.total_elevation_gain);
  const calories = num(a.calories);
  const avgSpeedKmh = num(a.average_speed) * 3.6;
  const maxSpeedKmh = num(a.max_speed) * 3.6;
  const avgHeartrate = num(a.average_heartrate);
  const maxHeartrate = num(a.max_heartrate);
  const kudos = num(a.kudos_count);
  const achievementCount = num(a.achievement_count);
  const sufferScore = num(a.suffer_score);

  const ts = new Date(start).getTime() * 1000000;

  const fields = [
    `activity_count=1i`,
    `distance_km=${distanceKm}`,
    `duration_min=${durationMin}`,
    `elapsed_min=${elapsedMin}`,
    `elevation_m=${elevationM}`,
    `calories=${calories}`,
    `avg_speed_kmh=${avgSpeedKmh}`,
    `max_speed_kmh=${maxSpeedKmh}`,
    `avg_heartrate=${avgHeartrate}`,
    `max_heartrate=${maxHeartrate}`,
    `kudos=${kudos}i`,
    `achievement_count=${achievementCount}i`,
    `suffer_score=${sufferScore}`,
    `activity_name="${escFieldString(name)}"`
  ];

  lines.push(
    `sport_activity,source=strava,sport_type=${escTag(type)},activity_id=${escTag(id)} ${fields.join(',')} ${ts}`
  );

  compact.push({
    date: start,
    id,
    name,
    type,
    distance_km: Number(distanceKm.toFixed(2)),
    duration_min: Number(durationMin.toFixed(1)),
    elapsed_min: Number(elapsedMin.toFixed(1)),
    elevation_m: Number(elevationM.toFixed(0)),
    calories: calories,
    avg_speed_kmh: Number(avgSpeedKmh.toFixed(2)),
    max_speed_kmh: Number(maxSpeedKmh.toFixed(2)),
    avg_heartrate: avgHeartrate,
    max_heartrate: maxHeartrate,
    suffer_score: sufferScore || null
  });
}

const totals = compact.reduce((acc, a) => {
  acc.activities += 1;
  acc.duration_min += a.duration_min || 0;
  acc.distance_km += a.distance_km || 0;
  acc.elevation_m += a.elevation_m || 0;
  acc.calories += a.calories || 0;

  acc.by_type[a.type] = acc.by_type[a.type] || {
    count: 0,
    duration_min: 0,
    distance_km: 0
  };

  acc.by_type[a.type].count += 1;
  acc.by_type[a.type].duration_min += a.duration_min || 0;
  acc.by_type[a.type].distance_km += a.distance_km || 0;

  return acc;
}, {
  activities: 0,
  duration_min: 0,
  distance_km: 0,
  elevation_m: 0,
  calories: 0,
  by_type: {}
});

totals.duration_min = Number(totals.duration_min.toFixed(1));
totals.distance_km = Number(totals.distance_km.toFixed(2));
totals.elevation_m = Number(totals.elevation_m.toFixed(0));
totals.calories = Number(totals.calories.toFixed(0));

return [
  {
    json: {
      influx_activity_line_protocol: lines.join('\n'),
      activity_count: compact.length,
      strava_compact: compact,
      totals
    }
  }
];

const input = $json;

let raw =
  input.output?.[0]?.content?.[0]?.text ||
  input.content?.[0]?.text ||
  input.text ||
  input.output ||
  input.response ||
  input.message ||
  input.data ||
  input.result ||
  JSON.stringify(input);

if (typeof raw !== 'string') {
  raw = JSON.stringify(raw);
}

raw = raw
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

let d;

try {
  d = JSON.parse(raw);
} catch (e) {
  d = {
    score: "?",
    status: "unbekannt",
    summary_short: raw,
    knee_rehab_feedback: "",
    weight_feedback: "",
    bmi_feedback: "",
    next_week_recommendation: "",
    avoid_next_week: [],
    workout_links: []
  };
}

const avoid = Array.isArray(d.avoid_next_week)
  ? d.avoid_next_week.join(", ")
  : d.avoid_next_week || "";

const links = Array.isArray(d.workout_links)
  ? d.workout_links
      .map((l, i) => `${i + 1}. ${l.title}\n${l.url}\nWarum: ${l.why || "-"}`)
      .join("\n\n")
  : "-";

return [
  {
    json: {
      telegram_text:
`🏃‍♂️ Sportanalyse letzte Woche

Score: ${d.score ?? "?"}/100
Status: ${d.status ?? "-"}

Kurzfassung:
${d.summary_short ?? "-"}

Kreuzband-Reha:
${d.knee_rehab_feedback ?? "-"}

Gewicht:
${d.weight_feedback ?? "-"}

BMI:
${d.bmi_feedback ?? "-"}

Empfehlung nächste Woche:
${d.next_week_recommendation ?? "-"}

Vermeiden:
${avoid || "-"}

Passende Übungen / Workouts:
${links || "-"}

Hinweis:
Bei Schmerzen, Schwellung, Instabilität oder Wärmegefühl im Knie Training reduzieren und Physio/Arzt fragen.`
    }
  }
];

const response = $json;

if (!response.ok) {
  throw new Error(response.error || "Health Auto Export Bridge Fehler");
}

const healthData =
  response.json?.result ||
  response.json ||
  response.raw ||
  response;

return [
  {
    json: {
      health_auto_export_raw: healthData,
      health_auto_export_meta: {
        days: response.days,
        start: response.start,
        end: response.end,
        metrics: response.metrics
      }
    }
  }
];

